    setOfficeTasks(prev=>(prev||[]).map(tk=>(tk.messages||[]).some(m=>isUnreadForUser(m,CURRENT_USER))?{...tk,messages:tk.messages.map(m=>isUnreadForUser(m,CURRENT_USER)?{...m,readBy:[...(m.readBy||[]),CURRENT_USER]}:m)}:tk));
