  const deleteMessages=(ids)=>{
    if(!sel||!ids||!ids.length)return;
    if(isAdmin){
      ids.filter(id=>String(id).startsWith("ctr-"))
        .forEach(id=>ctrRemove("contractor_messages",String(id).slice(4)).catch(()=>{}));
    }
    const idset=new Set(ids);
    setSharedProps(prev=>prev.map(p=>{
      if(p.id!==sel.id)return p;
      const messages=(p.messages||[]).filter(m=>!idset.has(m.id));
      const tasks=(p.tasks||[]).map(t=>({...t,messages:(t.messages||[]).filter(m=>!idset.has(m.id))}));
      return {...p,messages,tasks};
    }));
  };
  // Delete media picked in the gallery. Strips just the chosen photos/videos:
  // a photo-grid message keeps its other photos, a message with text keeps the
